    associatedtype Output
    func subscribe<S: Subscriber>(_ s: S) where S.Input == Output
}

struct AnyPublisher<Output>: Publisher {
    private let box: (Any) -> Void
    init<P: Publisher>(_ p: P) where P.Output == Output {
        self.box = { _ in /* ... */ }
    }
    func subscribe<S: Subscriber>(_ s: S) where S.Input == Output {
        box(s)
    }
}

actor ImageCache {
    private var cache: [URL: UIImage] = [:]
    func image(for url: URL) async -> UIImage? {
        if let cached = cache[url] { return cached }
        let data = try? await URLSession.shared.data(from: url).0
        let img = data.flatMap(UIImage.init(data:))
        if let img = img { cache[url] = img }
        return img
    }
}

