struct AnyEquatable: Equatable {
    private let isEqual: (Any) -> Bool
    private let value: Any
    init<T: Equatable>(_ v: T) {
        self.value = v
        self.isEqual = { ($0 as? T) == v }
    }
    static func ==(l: AnyEquatable, r: AnyEquatable) -> Bool {
        l.isEqual(r.value)
    }
}

